import React, { useState } from 'react';
import '../assets/styles/WhatsApp.css';
import RefreshIcon from '@mui/icons-material/Refresh';

const WhatsApp = () => {
  const [errorMessage, setErrorMessage] = useState('');
  const [qrCodeImage, setQrCodeImage] = useState(null); // Stochează imaginea codului QR
  const [isLoading, setIsLoading] = useState(false);
  const [isConnected, setIsConnected] = useState(false); // Stare pentru a ști dacă utilizatorul este conectat

  // Funcția pentru a trimite cererea de activare a aplicației WhatsApp
  const handleRequest = (url, callback) => {
    fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      }
    })
    .then(response => response.json())
    .then(data => {
      if (!data.success) {
        setErrorMessage(data.message);
      } else {
        setErrorMessage('');
        if (callback) callback(data);
      }
    })
    .catch(error => {
      console.error('Error:', error);
      setErrorMessage('A apărut o eroare.');
    });
  };

  // Funcția pentru a aduce WhatsApp în față
  const handleActivateWhatsApp = () => {
    handleRequest('/shortcuts/whatsapp/activate-whatsapp/');
  };

  // Funcția pentru a captura screenshot-ul și a verifica dacă utilizatorul este conectat
  const handleCaptureQRCode = () => {
    setIsLoading(true);
    handleRequest('/shortcuts/whatsapp/capture-qr-whatsapp/', (data) => {
      if (data.qr_code_path) {
        setQrCodeImage(`${data.qr_code_path}?${new Date().getTime()}`); // Setăm imaginea screenshot-ului și forțăm actualizarea
        setIsConnected(false); // Dacă QR este prezent, utilizatorul nu este conectat
      } else {
        setIsConnected(true); // Utilizatorul este deja conectat
      }
      setIsLoading(false);
    });
  };

  return (
    <div className="whatsapp-container">
      <h1 className="title">WhatsApp</h1>
      <div className="button-container">
        <button onClick={handleActivateWhatsApp} className="button activate-whatsapp-button">
          <RefreshIcon className="button-icon" /> Adu în față WhatsApp
        </button>
        <button onClick={handleCaptureQRCode} className="button capture-qr-button">
          {isLoading ? "Se încarcă..." : "Conectare"}
        </button>
      </div>

      {/* Afișează codul QR doar dacă utilizatorul nu este conectat */}
      {qrCodeImage && !isConnected && (
        <div className="qr-code-container">
          <h2>Scanează acest cod QR pentru a te conecta:</h2>
          <img src={qrCodeImage} alt="QR Code" className="qr-code-image" />
        </div>
      )}

      {/* Afișează un mesaj dacă utilizatorul este deja conectat */}
      {isConnected && (
        <div className="connected-message">
          <h2>Utilizatorul este deja conectat la WhatsApp!</h2>
        </div>
      )}

      {/* Afișează un mesaj de eroare dacă este cazul */}
      {errorMessage && <div className="error-message">{errorMessage}</div>}
    </div>
  );
};

export default WhatsApp;
